mapper.select:
select spsm.id as rowId, spsm.member_id as memberId, puser.name as memberName, spsm.author_type_code as authorTypeCode, ccspt.name as authorTypeName, spsm.sex as sex, ccsti.code as titleCode,ccsti.name as titleName, csel.code as eduLevelCode,csel.name as eduLevelName, spsm.work_ratio as workRatio,spsm.work_time as workTime, sauthororder.code as ranking,sauthororder.name as rankingName,spsm.note as note,spsm.work_ratio as wordRatio from srm_project_solicit_member spsm left join ct_srm_user puser on puser.id=spsm.member_id
left join ct_srm_dept fdept on fdept.id=spsm.dept_code left join ct_srm_person_type ccspt on ccspt.code=spsm.author_type_code left join ct_srm_title_info ccsti on ccsti.code=spsm.title_code left join ct_srm_edu_level csel on csel.code=spsm.edu_level_code left join ct_srm_paper_author_order sauthororder on sauthororder.code=spsm.ranking
where spsm.soli_proj_id=#{parentId}
